  1	import * as React from 'react';
  2	import {
  3	  EmptyState,
  4	  EmptyStateBody,
  5	  EmptyStateIcon,
  6	  EmptyStateVariant,
  7	  EmptyStateHeader,
  8	  EmptyStateFooter
  9	} from '@patternfly/react-core';
 10	import { kialiStyle } from 'styles/StyleUtils';
 11	import * as _ from 'lodash';
 12	import { KialiIcon } from '../../config/KialiIcon';
 13	import { DecoratedMeshElements } from 'types/Mesh';
 14	import { IntervalInMilliseconds } from 'types/Common';
 15	import { RefreshIntervalManual } from 'config/Config';
 16	import { t } from 'utils/I18nUtils';
 17	
 18	type EmptyMeshLayoutProps = {
 19	  action?: any;
 20	  elements?: DecoratedMeshElements;
 21	  isLoading?: boolean;
 22	  isError: boolean;
 23	  isMiniMesh: boolean;
 24	  loaded: boolean;
 25	  refreshInterval: IntervalInMilliseconds;
 26	  error?: string;
 27	};
 28	
 29	const emptyStateStyle = kialiStyle({
 30	  height: '98%',
 31	  marginRight: 'auto',
 32	  marginLeft: 'auto',
 33	  marginBottom: 10,
 34	  marginTop: 10
 35	});
 36	
 37	type EmptyMeshLayoutState = {};
 38	
 39	export class EmptyMeshLayout extends React.Component<EmptyMeshLayoutProps, EmptyMeshLayoutState> {
 40	  shouldComponentUpdate(nextProps: EmptyMeshLayoutProps) {
 41	    const currentIsEmpty = this.props.elements === undefined || _.isEmpty(this.props.elements.nodes);
 42	    const nextIsEmpty = nextProps.elements === undefined || _.isEmpty(nextProps.elements.nodes);
 43	
 44	    // Update if we have elements and we are not loading
 45	    if (!nextProps.isLoading && !nextIsEmpty) {
 46	      return true;
 47	    }
 48	
 49	    // Update if we are going from having no elements to having elements or vice versa
 50	    if (currentIsEmpty !== nextIsEmpty) {
 51	      return true;
 52	    }
 53	
 54	    // Do not update if we have elements, as this means we are refreshing
 55	    return nextIsEmpty;
 56	  }
 57	
 58	  render() {
 59	    if (this.props.isError) {
 60	      return (
 61	        <EmptyState id="empty-mesh-error" variant={EmptyStateVariant.lg} className={emptyStateStyle}>
 62	          <EmptyStateHeader
 63	            titleText={t('Error loading Mesh')}
 64	            icon={<EmptyStateIcon icon={KialiIcon.Error} />}
 65	            headingLevel="h5"
 66	          />
 67	          <EmptyStateBody>{this.props.error}</EmptyStateBody>
 68	        </EmptyState>
 69	      );
 70	    }
 71	    if (this.props.isLoading) {
 72	      return (
 73	        <EmptyState id="empty-mesh-is-loading" variant={EmptyStateVariant.lg} className={emptyStateStyle}>
 74	          <EmptyStateHeader titleText={t('Loading Mesh')} headingLevel="h5" />
 75	        </EmptyState>
 76	      );
 77	    }
 78	
 79	    if (this.props.refreshInterval === RefreshIntervalManual && !this.props.loaded && !this.props.isMiniMesh) {
 80	      return (
 81	        <EmptyState
 82	          id="empty-graph-manual"
 83	          data-test="manual-refresh"
 84	          variant={EmptyStateVariant.lg}
 85	          className={emptyStateStyle}
 86	        >
 87	          <EmptyStateHeader titleText={t('Manual refresh required')} headingLevel="h5" />
 88	          <EmptyStateBody>
 89	            {t(
 90	              'The refresh interval is set to "Manual". To render the mesh, select your desired filters and options and then click the Refresh button. Or, if preferred, change the setting to the desired interval.'
 91	            )}
 92	          </EmptyStateBody>
 93	        </EmptyState>
 94	      );
 95	    }
 96	
 97	    const isMeshEmpty = !this.props.elements || !this.props.elements.nodes || this.props.elements.nodes.length < 1;
 98	    if (isMeshEmpty && !this.props.isMiniMesh) {
 99	      return (
100	        <EmptyState id="empty-mesh" variant={EmptyStateVariant.lg} className={emptyStateStyle}>
101	          <EmptyStateHeader titleText={t('Empty Mesh')} headingLevel="h5" />
102	          <EmptyStateBody>
103	            {t(
104	              'There is currently no mesh information available. This may mean you do not have permission to see any mesh information or have no access to any of the mesh namespaces.'
105	            )}
106	          </EmptyStateBody>
107	          <EmptyStateFooter></EmptyStateFooter>
108	        </EmptyState>
109	      );
110	    }
111	
112	    if (isMeshEmpty && this.props.isMiniMesh) {
113	      return (
114	        <EmptyState id="empty-mini-mesh" variant={EmptyStateVariant.lg} className={emptyStateStyle}>
115	          <EmptyStateHeader titleText={t('Empty Mesh')} headingLevel="h5" />
116	          <EmptyStateBody>{t('No mesh information available.')}</EmptyStateBody>
117	        </EmptyState>
118	      );
119	    }
120	
121	    return this.props.children;
122	  }
123	}

